#include<bits/stdc++.h>
using namespace std;
long long b[300010];
long long gcd(long long x,long long y)
{
    if(y==0)
    {
        return x;
    }
    return (x%y==0?y:gcd(y,x%y));
}
struct segment_tree
{
    struct node
    {
        long long l,r,lson,rson;
        long long sum,max1,min1,gcd;
    }a[900010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=a[a[x].lson].sum+a[a[x].rson].sum;
        a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
        a[x].min1=min(a[a[x].lson].min1,a[a[x].rson].min1);
        a[x].gcd=gcd(a[a[x].lson].gcd,a[a[x].rson].gcd);
    }
    long long init(long long b[],long long l,long long r)
    {
        long long x=++cnt;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum=a[x].max1=a[x].min1=a[x].gcd=b[l];
            return x;
        }
        long long mid=(l+r)>>1;
        a[x].lson=init(b,l,mid);
        a[x].rson=init(b,mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p,long long v)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].sum=a[x].max1=a[x].min1=a[x].gcd=v;
            return;
        }
        update(a[x].lson,p,v);
        update(a[x].rson,p,v);
        pushup(x);
    }
    long long getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        return getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r);
    }
    long long getmax(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return -1e18;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].max1;
        }
        return max(getmax(a[x].lson,l,r),getmax(a[x].rson,l,r));
    }
    long long getmin(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 1e18;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].min1;
        }
        return min(getmin(a[x].lson,l,r),getmin(a[x].rson,l,r));
    }
    long long getgcd(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].gcd;
        }
        return gcd(getgcd(a[x].lson,l,r),getgcd(a[x].rson,l,r));
    }
}t,cha;
long long v[300010];
bool check(long long l,long long r,long long k)
{
    if(l==r)
    {
        return true;
    }
    long long max1=t.getmax(1,l,r),min1=t.getmin(1,l,r),sum=t.getsum(1,l,r),g=cha.getgcd(1,l+1,r);
    if(k==0)
    {
        return max1==min1;
    }
    if(max1-min1!=(r-l)*k)
    {
        return false;
    }
    if((max1-min1)%(r-l)!=0||(max1-min1)/(r-l)!=k)
    {
        return false;
    }
    if(sum*2!=(max1+min1)*(r-l+1))
    {
        return false;
    }
    if(g%k!=0)
    {
        return false;
    }
    if(cha.getmin(1,l+1,r)==0)
    {
        return false;
    }
    for(long long i=l;i+3<=r;i++)
    {
        long long x=i,y=i+2;
        if(b[x]==b[y])
        {
            return false;
        }
    }
    for(long long i=l;i+7<=r;i++)
    {
        long long x=i,y=i+7;
        if(b[x]==b[y])
        {
            return false;
        }
    }
    return true;
}
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
        v[i]=b[i]-b[i-1];
    }
    t.init(b,1,n);
    cha.init(v,1,n);
    long long cnt=0;
    while(m--)
    {
        long long op,x,y,k;
        scanf("%lld%lld%lld",&op,&x,&y);
        x^=cnt;
        y^=cnt;
        if(op==1)
        {
            b[x]=y;
            t.update(1,x,y);
            v[x]=b[x]-b[x-1];
            cha.update(1,x,v[x]);
            v[x+1]=b[x+1]-b[x];
            if(x<n)
            {
                cha.update(1,x+1,v[x+1]);
            }
        }
        else
        {
            scanf("%lld",&k);
            k^=cnt;
            if(check(x,y,k))
            {
                printf("Yes\n");
                cnt++;
            }
            else
            {
                printf("No\n");
            }
        }
    }
    return 0;
}
